import { useParams } from "react-router-dom";
import { useEffect, useState } from "react";
import "./SalaryHistory.css";

function SalaryHistory() {
  const { id } = useParams();
  const [employee, setEmployee] = useState(null);
  const [salaryRecords, setSalaryRecords] = useState([]);

  useEffect(() => {
    // Get Employees
    const employees = JSON.parse(localStorage.getItem("employees")) || [];
    const emp = employees.find(e => String(e.id) === String(id));
    setEmployee(emp);

    // Get Salary History (stored separately)
    const allSalary = JSON.parse(localStorage.getItem("salaryHistory")) || [];

    const empSalary = allSalary.filter(s => String(s.empId) === String(id));
    setSalaryRecords(empSalary);

  }, [id]);

  if (!employee) {
    return <p>No Employee Found</p>;
  }

  return (
    <div className="salary-container">
      <h2>Salary History</h2>

      <div className="employee-info">
        <p><strong>Name:</strong> {employee.name}</p>
        <p><strong>Employee ID:</strong> {employee.empId}</p>
        <p><strong>Department:</strong> {employee.department}</p>
      </div>

      <table className="salary-table">
        <thead>
          <tr>
            <th>S No</th>
            <th>Salary</th>
            <th>Allowance</th>
            <th>Deduction</th>
            <th>Total</th>
            <th>Pay Date</th>
          </tr>
        </thead>

        <tbody>
          {salaryRecords.length > 0 ? (
            salaryRecords.map((rec, index) => (
              <tr key={index}>
                <td>{index + 1}</td>
                <td>{rec.salary}</td>
                <td>{rec.allowance}</td>
                <td>{rec.deduction}</td>
                <td>{rec.total}</td>
                <td>{rec.date}</td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="6" style={{ textAlign: "center" }}>
                No Salary History Found
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

export default SalaryHistory;
